#!/usr/bin/env node
/* eslint-disable no-console */
/**
 * Detect the current git branch and write it to
 * `src/config/build-config.generated.ts` so the rest of the app can
 * import a typed constant for which backend to talk to.
 *
 * This script runs from two places:
 *
 *   1. `postinstall` — guarantees the generated file exists on a fresh
 *      `npm install`, so TypeScript / Jest / IDE tooling have something
 *      to import before any bundle has been produced.
 *
 *   2. From `metro.config.js`, at the top of every Metro startup. Metro
 *      is the single bundling entry point for every distribution path:
 *      `npm run android` / `npm run ios` (debug), the Xcode "Bundle React
 *      Native code and images" phase (release Archives), and Gradle's
 *      `bundleReleaseJsAndAssets` task (release APK/AAB) all invoke
 *      Metro. Hooking metro.config.js means the value is always
 *      regenerated immediately before any code is bundled — no separate
 *      Xcode/Gradle changes needed.
 *
 * If git isn't available (e.g. shallow CI checkout, detached HEAD, repo
 * not initialised) we write `unknown`. The runtime side defaults to the
 * dev backend in that case — never prod — so a misconfigured build can't
 * accidentally point at production.
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

const REPO_ROOT = path.resolve(__dirname, "..");
const OUT_PATH = path.join(REPO_ROOT, "src/config/build-config.generated.ts");

function detectBranch() {
  try {
    return execSync("git rev-parse --abbrev-ref HEAD", {
      cwd: REPO_ROOT,
      stdio: ["ignore", "pipe", "ignore"],
    })
      .toString()
      .trim();
  } catch {
    return "unknown";
  }
}

function main() {
  const branch = detectBranch();
  // Type-annotate as `string` (not the literal) so consumers can
  // compare against "main"/"development" without TS flagging the
  // comparison as unintentional when the bundle happens to be built
  // from some other branch.
  const contents =
    "// AUTO-GENERATED by scripts/write-build-config.js — do not edit.\n" +
    "// The value is the git branch the bundle was built from. See\n" +
    "// src/config/env.ts for how it's mapped to an API base URL.\n" +
    `export const GIT_BRANCH: string = ${JSON.stringify(branch)};\n`;

  // Avoid unnecessary writes — Metro watches the source tree, and a
  // touched-but-identical file would cause a needless re-bundle in dev.
  const existing = fs.existsSync(OUT_PATH)
    ? fs.readFileSync(OUT_PATH, "utf8")
    : "";
  if (existing !== contents) {
    fs.writeFileSync(OUT_PATH, contents);
    console.log(`[build-config] git branch = ${branch} → ${OUT_PATH}`);
  }
}

main();
